  // resume rail — honors MediaTypes (Continue Watching=Video / Listening=Audio / Reading=Book) (L5)
  async function resumeItems(sp) {
    await L(); await ud.ensure(); await ensureKappa();
    const mediaTypes = (sp && sp.get("MediaTypes") || "").split(",").filter(Boolean);
    const out = [];
    for (const [id, u] of ud.entries()) {
      if (!(u.PlaybackPositionTicks > 0) || u.Played) continue;
      let it = null;
      if (id.startsWith("03")) { const rec = kappa.byId.get(id); it = rec && kappaDto(rec); }
      else if (id.startsWith("04")) { const e = epRecords.get(id); it = e && epDto(e); }
      else { const r = findRow(id); it = r && dto(r); }
      if (!it) continue;
      if (mediaTypes.length && !mediaTypes.includes(it.MediaType || "Video")) continue;
      out.push({ it, t: u.LastPlayedDate || "" });
    }
    out.sort((a, b) => (b.t + "").localeCompare(a.t + ""));
    return { Items: out.slice(0, 24).map((x) => x.it), TotalRecordCount: out.length };
  }

  // NextUp (L1) — for each series with watched episodes, the next unwatched one. SELF-WARMING across
  // SW restarts: the watched episode ids encode (series, season), so a cold instance re-loads exactly
  // those seasons through tmdb — whose responses the binding κ-caches, making the re-load offline+fast.
  async function nextUp() {
    await ud.ensure(); await L();
    const best = new Map();   // seriesTmdb → {season, ep}
    for (const [id, u] of ud.entries()) {
      if (!id.startsWith("04") || !u.Played) continue;
      const { series, season, ep } = decodeEp(id);
      const cur = best.get(series);
      if (!cur || season > cur.season || (season === cur.season && ep > cur.ep)) best.set(series, { season, ep });
    }
    const items = [];
    for (const [series, { season, ep }] of best) {
      const name = (lib.rowByKey("t" + series) || {}).t || "";
      if (!epRecords.has(epId(series, season, ep + 1))) await loadSeason(series, season, name);
      let next = epRecords.get(epId(series, season, ep + 1));
      if (!next) { await loadSeason(series, season + 1, name); next = epRecords.get(epId(series, season + 1, 1)); }
      if (next) items.push(epDto(next));
    }
    return { Items: items.slice(0, 24), TotalRecordCount: items.length };
  }

  // detail enrichment (movies + series) via the atomic TMDB record — lazy, cache lives in the injected tmdb
