async function imageBytes(ref) {
  const c = await caches.open("holo-jf-img");
  const key = "/img/" + (ref.kappaHex || ref.tmdbPath && (ref.size + ref.tmdbPath) || ref.url);
  const hit = await c.match(key);
  if (hit) return hit.clone();
  let out = null;
  if (ref.kappaHex) {
    const bytes = await kappaSource.object(ref.kappaHex);
    if (bytes && (await sha256hex(bytes)) === ref.kappaHex) out = new Response(bytes, { headers: { "content-type": ref.contentType || "image/jpeg", "cache-control": "max-age=31536000" } });
  } else {
    const raw = ref.tmdbPath ? "image.tmdb.org/t/p/" + ref.size + ref.tmdbPath : String(ref.url).replace(/^https?:\/\//, "");
    const res = await fetch("https://images.weserv.nl/?url=" + encodeURIComponent(raw), { mode: "cors" });
    if (res.ok) out = new Response(await res.arrayBuffer(), { headers: { "content-type": res.headers.get("content-type") || "image/jpeg", "cache-control": "max-age=31536000" } });
  }
  if (!out) return new Response("", { status: 404 });
  await c.put(key, out.clone());
  return out.clone();
}

// ── stream bytes — mirror objects proxy with synthesized Content-Range; plain sources 302 out ───────────
async function streamBytes(req, ref) {
  if (ref.redirect) return Response.redirect(ref.url, 302);           // non-COEP page: the media element streams it natively
  const range = req.headers.get("range");
  const upstream = await fetch(ref.url, { mode: "cors", headers: range ? { range } : {} });
  if (!upstream.ok && upstream.status !== 206) return new Response("", { status: upstream.status });
  const h = new Headers({ "accept-ranges": "bytes", "content-type": upstream.headers.get("content-type") || "video/mp4" });
  for (const k of ["content-range", "content-length"]) { const v = upstream.headers.get(k); if (v) h.set(k, v); }
  if (upstream.status === 206 && !h.get("content-range") && range) {
    const s = synthRange(range, ref.bytes);
    if (s) { h.set("content-range", s.contentRange); if (!h.get("content-length")) h.set("content-length", String(s.contentLength)); }
  }
  return new Response(upstream.body, { status: upstream.status, headers: h });   // stream through, never buffer
}

// ── trace + dispatch ─────────────────────────────────────────────────────────────────────────────────────
const trace = [];
async function dispatch(req) {
  const u = new URL(req.url);
  const p = u.pathname;
  // scope-relative view: live the app sits at /Q/apps/jellyfin/, in the harness at /
  const rel = p.startsWith(SCOPE) ? "/" + p.slice(SCOPE.length) : p;
  if (/^\/(web|lib|feed|kappa|holo-jellyfin-(sw\.js|core\.mjs|music\.mjs)|index\.html$|__holo|holo-evicted\.json$|LICENSE)/.test(rel) || rel === "/") {
    if (rel === "/__holo/trace") return new Response(JSON.stringify(trace), { headers: { "content-type": "application/json" } });
    if (/^\/web\/serviceworker\.js$/.test(rel)) return new Response("", { status: 404 });   // the PWA hijacker stays dead
    const net = await fetch(req).catch(() => null);
    if (net && net.ok) return net;
    const rescued = await rescue(rel.slice(1) || "index.html");       // evicted app bytes re-derive from the mirror
    return rescued || net || new Response("", { status: 504 });
  }
  let body = null;
  if (req.method === "POST") { try { body = await req.clone().json(); } catch {} }
  await ensureMusic();                                                  // the Music library is populated before any route runs
  const r = await server.route(req.method, u.origin + rel + u.search, body);
  trace.push({ method: req.method, path: rel, matched: !r.unmatched }); if (trace.length > 800) trace.shift();
  if (r.stream) return streamBytes(req, r.stream);
  if (r.image) return imageBytes(r.image);
  if (r.bytes) return new Response(new Uint8Array(r.bytes), { headers: { "content-type": "application/octet-stream" } });
  if (r.css != null) return new Response(r.css, { status: r.status, headers: { "content-type": "text/css" } });
  if (r.status === 204) return new Response(null, { status: 204 });
  return new Response(JSON.stringify(r.json ?? {}), { status: r.status, headers: { "content-type": "application/json" } });
}

self.addEventListener("install", () => self.skipWaiting());
self.addEventListener("activate", (e) => e.waitUntil(self.clients.claim()));
self.addEventListener("fetch", (e) => {
  const u = new URL(e.request.url);
  if (u.origin !== self.location.origin) return;
  e.respondWith(dispatch(e.request).catch((err) => new Response(JSON.stringify({ holoError: String(err && err.message || err) }), { status: 500, headers: { "content-type": "application/json" } })));
});

